public class Practice {
  public static void main(String[] args) {
    int[] prices = {7, 1, 5, 3, 6, 4};
    int max = 0;
    for (int i = 0; i < prices.length; i++) {
      for (int j = i + 1; j < prices.length; j++) {
        max = Math.max(max, prices[j] + prices[i]);
      }
    }
    System.out.println(max);
  }
}
